const raw = $input.first().json;
const body = raw.body || raw;
const sessionId = String(body.sessionId || body.uuid || '').trim()
  || 'auto_' + Date.now() + '_' + Math.random().toString(36).substr(2,6);
const chatInput = String(body.message || body.chatInput || '').trim();
if (!chatInput) throw new Error('message es requerido');
return [{ json: { sessionId, chatInput } }];

let inp = {};
try {
  if (typeof query !== 'undefined' && query) {
    inp = (typeof query === 'string') ? JSON.parse(query) : query;
  } else {
    const raw = $input.first().json;
    const q = raw.query || raw;
    inp = (typeof q === 'string') ? JSON.parse(q) : q;
  }
} catch(e) {
  // El agente a veces manda texto libre en vez de JSON: "producto: X, m2: 221"
  inp = {};
  const src = (typeof query === 'string') ? query : String((($input.first().json||{}).query) || '');
  src.split(',').forEach(function(pair) {
    const idx = pair.indexOf(':');
    if (idx === -1) return;
    const key = pair.slice(0, idx).trim().toLowerCase();
    const value = pair.slice(idx + 1).trim();
    inp[key] = value;
  });
}

const producto = String(inp.producto || '').toLowerCase();
const m2 = parseFloat(inp.m2) || 0;
const conInst = inp.con_instalacion === true || inp.con_instalacion === 'true' || inp.con_instalacion === 'SI' || inp.con_instalacion === 'si';

const PRECIOS = {
  '7mm': 28500,
  '10mm': 22900,
  '15mm': 26000,
  'luxury': 28500,
  'emerald': 28500,
  'soft touch': 22900,
  'soft': 22900,
  'pet': 26000,
  'friendly': 26000,
  'futbolito 50mm': 35000,
  '50mm': 35000,
  'futbolito 60mm': 32000,
  '60mm': 32000,
  'futbol 7': 35000,
  'fútbol 7': 35000,
  'futbol7': 35000,
  'fútbol7': 35000,
  'futbol 11': 32000,
  'fútbol 11': 32000,
  'futbol11': 32000,
  'fútbol11': 32000,
  'tenis': 38000,
  'padel': 38000,
  'pádel': 38000,
  'monofilamento': 38000,
  'deportivo': 34000
};

let precioPorM2 = 0;
for (const key in PRECIOS) {
  if (producto.indexOf(key) !== -1) { precioPorM2 = PRECIOS[key]; break; }
}

if (m2 <= 0) {
  return 'Se necesitan los m² para calcular el precio. ¿Me confirmas la superficie?';
}
if (precioPorM2 === 0) {
  return 'Producto no reconocido: ' + inp.producto + '. ¿Puedes confirmar el nombre exacto del producto?';
}

const m2Margen = Math.ceil(m2 * 1.10);
const subtotalPasto = m2Margen * precioPorM2;
const subtotalInst = conInst ? m2Margen * 4500 : 0;
const total = subtotalPasto + subtotalInst;
const fmt = function(n) { return n.toLocaleString('es-CL'); };

let resumen = inp.producto + ' — $' + fmt(precioPorM2) + '/m²\n';
resumen += 'Superficie: ' + m2 + ' m² → ' + m2Margen + ' m² (con margen técnico 10%)\n';
resumen += 'Subtotal pasto: $' + fmt(subtotalPasto);
resumen += conInst ? ('\nInstalación: $' + fmt(subtotalInst)) : '\nInstalación: no incluida';
resumen += '\nTOTAL: $' + fmt(total) + ' (total exacto: ' + total + ')';

return resumen;

// En toolCode, el LLM pasa los datos como variable 'query' (string JSON)
let inp = {};
try {
  if (typeof query !== 'undefined' && query) {
    inp = (typeof query === 'string') ? JSON.parse(query) : query;
  } else {
    const raw = $input.first().json;
    const q = raw.query || raw;
    inp = (typeof q === 'string') ? JSON.parse(q) : q;
  }
} catch(e) { inp = {}; }

const year = new Date().getFullYear();
const seq = String(Date.now()).slice(-5);
const numero = 'COT-' + year + '-' + seq;

const m2 = Math.round(parseFloat(String(inp.m2 || inp.metros_cuadrados || '0').replace(/[^0-9.]/g, '')) || 0);
const rawTotal = String(inp.total || '0').replace(/[^0-9]/g, '');
const total = parseInt(rawTotal) || 0;

const nombre = String(inp.nombre || '');
const rut = String(inp.rut || '');
const email = String(inp.email || inp.correo || '');
const direccion = String(inp.direccion || '');
const producto = String(inp.producto || '');
const telefono = String(inp.telefono || '');

const fmt = n => Number(n).toLocaleString('es-CL');
const totalStr = total > 0 ? '$' + fmt(total) : 'A cotizar';
const footerStr = total > 0
  ? 'Escribe PAGAR para continuar con el pago.'
  : 'Un asesor te contactará con el precio final.';

return '\u2705 Cotizaci\u00f3n N\u00b0 ' + numero + ' generada.\n\ud83d\udc64 ' + nombre + ' \u2014 ' + rut + '\n\ud83d\udce7 ' + email + (telefono ? '\n\ud83d\udcde ' + telefono : '') + '\n\ud83d\udccd ' + direccion + '\n\ud83c\udf3f ' + producto + ' \u2014 ' + m2 + ' m\u00b2\n\ud83d\udcb0 Total: ' + totalStr + '\n\n' + footerStr;

let inp = {};
try {
  if (typeof query !== 'undefined' && query) {
    inp = (typeof query === 'string') ? JSON.parse(query) : query;
  } else {
    const raw = $input.first().json;
    const q = raw.query || raw;
    inp = (typeof q === 'string') ? JSON.parse(q) : q;
  }
} catch(e) { inp = {}; }

const numero = String(inp.numero_cotizacion || inp.numero || '').trim();
const total  = parseInt(String(inp.total || '0').replace(/[^0-9]/g, '')) || 0;

if (!numero || total <= 0) {
  return 'Para procesar el pago necesito el número de cotización y el monto total. ¿Puedes confirmarlos?';
}

return '[PAGAR_MP:numero=' + numero + ', total=' + total + ']';

const agentOutput = $input.first().json;
const message = String(agentOutput.output || '');

// Ignorar markers de otros nodos (buscar/pagar)
if (message.includes('[BUSCAR_COT:') || message.includes('[PAGAR_MP:')) {
  return [{ json: agentOutput }];
}

// Solo procesar si el mensaje contiene un número de cotización
const cotMatch = message.match(/C[O0]T-([0-9]{4}-[0-9]+)/i);
if (!cotMatch) {
  return [{ json: agentOutput }];
}

// Forzamos siempre COT- con letra O para evitar confusiones con el cero
const numero = 'COT-' + cotMatch[1];
let nombre = '', rut = '', email = '', telefono = '', direccion = '', producto = '', m2 = 0, total = 0;

const lines = message.split('\n');
for (const line of lines) {
  const l = line.trim();
  if (l.includes('\ud83d\udc64')) {
    const parts = l.replace(/^.*\ud83d\udc64\s*/, '').split(' \u2014 ');
    nombre = (parts[0] || '').trim();
    rut = (parts[1] || '').trim();
  } else if (l.includes('\ud83d\udce7')) {
    email = l.replace(/^.*\ud83d\udce7\s*/, '').trim();
  } else if (l.includes('\ud83d\udcde')) {
    telefono = l.replace(/^.*\ud83d\udcde\s*/, '').trim();
  } else if (l.includes('\ud83d\udccd')) {
    direccion = l.replace(/^.*\ud83d\udccd\s*/, '').trim();
  } else if (l.includes('\ud83c\udf3f')) {
    const parts = l.replace(/^.*\ud83c\udf3f\s*/, '').split(' \u2014 ');
    producto = (parts[0] || '').trim();
    m2 = parseInt((parts[1] || '').replace(/[^0-9]/g, '')) || 0;
  } else if (l.includes('\ud83d\udcb0')) {
    const afterDollar = l.indexOf('$');
    if (afterDollar !== -1) {
      total = parseInt(l.slice(afterDollar + 1).replace(/[^0-9]/g, '')) || 0;
    } else {
      total = 0;
    }
  }
}

let sessionId = '';
try { sessionId = $('Extraer Input').first().json.sessionId || ''; } catch(e) {}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_KEY;

const quote = {
  numero,
  session_id: sessionId,
  nombre, rut, email, direccion, producto,
  m2, instalacion: true, total,
  estado: 'P'
};

try {
    await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/cotizaciones',
    headers: {
      'Content-Type': 'application/json',
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(quote)
  });
} catch(e) {
  console.error('Supabase error:', e.message);
}

return [{ json: { ...agentOutput, _customer_email: email, _quote_summary: message, _total: total } }];

const agentOutput = $input.first().json;
const message = String(agentOutput.output || '');

// Solo actuar si hay marker de pago emitido por Tool generar_pago
const pagoMatch = message.match(/\[PAGAR_MP:numero=([^,\s\]]+),\s*total=([0-9]+)\]/);
if (!pagoMatch) {
  return [{ json: agentOutput }];
}

const numero   = pagoMatch[1].trim().replace(/['"]/g, '').toUpperCase();
const total    = parseInt(pagoMatch[2]);
const row      = agentOutput._quote_data;
const MP_TOKEN = $env.MERCADOPAGO_ACCESS_TOKEN;

const fmt = n => Number(n).toLocaleString('es-CL');

let paymentUrl = '';
let mpError    = '';
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.mercadopago.com/checkout/preferences',
    headers: {
      'Authorization': 'Bearer ' + MP_TOKEN
    },
    json: true,
    body: {
      items: [{
        id: numero,
        title: 'Cotizacion ' + numero + ' - Cesped Sintetico ARM',
        quantity: 1,
        unit_price: total,
        currency_id: 'CLP'
      }],
      external_reference: numero
    }
  });
  paymentUrl = (resp.sandbox_init_point || resp.init_point || '').trim();
} catch(e) {
  mpError = String(e.message || e);
}

let newOutput;
if (paymentUrl) {
  if (row) {
    newOutput = 'ð³ Tu link de pago está listo para la cotización ' + numero + ':\n' + 'ð¤ ' + (row.nombre || '') + '\n' + 'ð ' + (row.direccion || '') + '\n' + 'ð¿ ' + (row.producto || '') + ' — ' + (row.m2 || 0) + ' m²\n' + 'ð° Total: $' + fmt(total) + '\n\n' + '[PAYMENT_URL:' + paymentUrl + ']';
  } else {
    newOutput = 'ð³ Tu link de pago está listo.\n' + 'ð ' + numero + '  |  ð° $' + fmt(total) + '\n\n' + '[PAYMENT_URL:' + paymentUrl + ']';
  }
} else {
  newOutput = 'ð³ Hubo un error generando el link para ' + numero + '. Por favor intenta nuevamente o contacta a soporte.';
}

return [{ json: { ...agentOutput, output: newOutput, _mp_url: paymentUrl, _total: total, _quote_data: row } }];

// toolCode sandbox: sin HTTP → solo emite marker para el nodo regular siguiente
let numero = '';
try {
  if (typeof query !== 'undefined' && query) {
    const q = (typeof query === 'string') ? query : JSON.stringify(query);
    const m = q.match(/C[O0]T-[0-9]{4}-[0-9]+/i);
    numero = m ? m[0].toUpperCase() : q.replace(/[^A-Z0-9-]/gi, '').toUpperCase().trim();
  }
} catch(e) { numero = ''; }

if (!numero || !numero.match(/^C[O0]T-/i)) {
  return 'Necesito el número de cotización exacto (formato COT-2026-XXXXX) para buscarla.';
}

// Retornamos el marcador directamente. El sistema se encarga de buscarlo en BD.
return '[BUSCAR_COT:numero=' + numero.toUpperCase() + ']';

const agentOutput = $input.first().json;
const message = String(agentOutput.output || '');

// Detectar marker de búsqueda O de pago para inyectar datos de la cotización
const buscarMatch = message.match(/\[BUSCAR_COT:numero=([^\s\]]+)\]/i);
const pagoMatch = message.match(/\[PAGAR_MP:numero=([^,\s\]]+)/i);
if (!buscarMatch && !pagoMatch) {
  return [{ json: agentOutput }];
}

// Remover posibles comillas que agregue el LLM y limpiar espacios
let numero = (buscarMatch ? buscarMatch[1] : pagoMatch[1]).trim().replace(/['"]/g, '').toUpperCase();

// === FIX IDOR: recuperar el session_id de la conversación actual ===
let sessionId = '';
try { sessionId = $('Extraer Input').first().json.sessionId || ''; } catch(e) {}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_KEY;
const fmt = n => Number(n || 0).toLocaleString('es-CL');

let newOutput;
try {
  // === FIX IDOR: el query ahora exige que numero Y session_id coincidan ===
  const buscarEnSupabase = async (num) => {
    return await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/cotizaciones?numero=eq.' + encodeURIComponent(num)
           + '&session_id=eq.' + encodeURIComponent(sessionId) + '&limit=1',
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
  };

  let resp = await buscarEnSupabase(numero);
  let data = Array.isArray(resp) ? resp : JSON.parse(String(resp));

  // Si no encuentra con COT, intentamos con C0T (o viceversa) — sigue exigiendo el mismo session_id
  if (data.length === 0) {
    const alternativo = numero.includes('COT') ? numero.replace('COT', 'C0T') : numero.replace('C0T', 'COT');
    resp = await buscarEnSupabase(alternativo);
    data = Array.isArray(resp) ? resp : JSON.parse(String(resp));
  }

  const row = data.length > 0 ? data[0] : null;

  // === FIX IDOR: mensaje genérico, no revela si el número existe para OTRA sesión ===
  if (!row) {
    newOutput = 'No encontramos esa cotización asociada a esta conversación. Si la generaste desde otro dispositivo o necesitas ayuda, contáctanos por WhatsApp para verificarla.';
    return [{ json: { ...agentOutput, output: newOutput } }];
  }

  if (row.estado === 'C') {
    newOutput = '⚠️ La cotización N° ' + row.numero + ' ya figura como PAGADA en nuestro sistema. No es posible volver a pagarla.';
    return [{ json: { ...agentOutput, output: newOutput } }];
  }

  const created = new Date(row.created_at);
  const diffDays = Math.ceil((new Date() - created) / (1000 * 60 * 60 * 24));
  if (row.estado === 'V' || diffDays > 10) {
    newOutput = '⚠️ La cotización N° ' + row.numero + ' ya no está vigente (han pasado más de 10 días). Por favor, genera una nueva.';
    return [{ json: { ...agentOutput, output: newOutput } }];
  }

  if (pagoMatch) {
    return [{ json: { ...agentOutput, _quote_data: row } }];
  }

  const inst = row.instalacion ? 'Con instalación' : 'Sin instalación';
  const totalStr = row.total > 0 ? '$' + fmt(row.total) : 'A confirmar';
  newOutput = '✅ Cotización N° ' + row.numero + ' encontrada.\n' + '👤 ' + (row.nombre || '—') + ' — ' + (row.rut || '') + '\n' + '📍 ' + (row.direccion || '—') + '\n' + '🌿 ' + (row.producto || '—') + ' — ' + (row.m2 || 0) + ' m²\n' + '🔧 ' + inst + '\n' + '💰 Total: ' + totalStr + '\n\n' + 'Escribe PAGAR para continuar con el pago.';
  return [{ json: { ...agentOutput, output: newOutput, _customer_email: row.email || '', _total: row.total || 0, _quote_data: row } }];

} catch(e) {
  newOutput = 'Error al procesar la cotización: ' + e.message;
}
return [{ json: { ...agentOutput, output: newOutput } }];

const inputData = $input.first().json;

// Solo registrar si tenemos link de pago generado
if (!inputData._mp_url) {
  return [{ json: inputData }];
}

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_KEY;

// CASO 1: Datos vienen de buscar_cotizacion (flujo pago desde cotización buscada)
let row = inputData._quote_data;

let sale;
if (row) {
  // Usar directamente los datos del objeto de la BD
  sale = {
    numero: row.numero || '',
    session_id: row.session_id || '',
    nombre: row.nombre || '',
    rut: row.rut || '',
    direccion: row.direccion || '',
    producto: row.producto || '',
    m2: parseInt(row.m2 || 0),
    instalacion: row.instalacion === true || String(row.instalacion).toLowerCase() === 'true',
    total: parseInt(inputData._total || row.total || 0),
    email: row.email || inputData._customer_email || '',
    created_at: new Date().toISOString(),
    estado: 'P'
  };
} else {
  // CASO 2: Datos deben ser extraídos del mensaje del pago (flujo cotización nueva)
  const message = String(inputData.output || '');

  // Extraer numero de cotizacion del mensaje
  const numMatch = message.match(/C[O0]T-[0-9]{4}-[0-9]+/i);
  const numero = numMatch ? numMatch[0].toUpperCase() : '';

  // Extraer total del mensaje
  let total = parseInt(inputData._total || 0);
  if (!total) {
    const totalMatch = message.match(/\$([0-9.,]+)/);
    if (totalMatch) total = parseInt(totalMatch[1].replace(/[.,]/g, '')) || 0;
  }

  // Extraer datos del texto con emojis (mismo patron que Guardar en Supabase)
  let nombre = '', rut = '', email = '', direccion = '', producto = '', m2 = 0;
  const lines = message.split('\n');
  for (const line of lines) {
    const l = line.trim();
    if (l.includes('\ud83d\udc64')) {
      const parts = l.replace(/^.*\ud83d\udc64\s*/, '').split(' \u2014 ');
      nombre = (parts[0] || '').trim();
      rut = (parts[1] || '').trim();
    } else if (l.includes('\ud83d\udccd')) {
      direccion = l.replace(/^.*\ud83d\udccd\s*/, '').trim();
    } else if (l.includes('\ud83c\udf3f')) {
      const parts = l.replace(/^.*\ud83c\udf3f\s*/, '').split(' \u2014 ');
      producto = (parts[0] || '').trim();
      m2 = parseInt((parts[1] || '').replace(/[^0-9]/g, '')) || 0;
    }
  }

  // Si no hay número de cotizacion no hay nada que grabar
  if (!numero) {
    return [{ json: inputData }];
  }

  let sessionId = '';
  try { sessionId = $('Extraer Input').first().json.sessionId || ''; } catch(e) {}

  sale = {
    numero,
    session_id: sessionId,
    nombre,
    rut,
    direccion,
    producto,
    m2,
    instalacion: true,
    total,
    email: inputData._customer_email || '',
    created_at: new Date().toISOString(),
    estado: 'P'
  };
}

try {
  // 1. Guardar la venta
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/venta',
    headers: {
      'Content-Type': 'application/json',
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify(sale)
  });

  // 2. Actualizar el estado de la cotizacion a 'C'
  if (sale.numero) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/cotizaciones?numero=eq.' + encodeURIComponent(sale.numero),
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({ estado: 'C' })
    });
  }
} catch(e) {
  console.error('Error en Registrar Venta o Actualizar Cotizacion:', e.message);
}

return [{ json: inputData }];
